static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    const gert::Shape *a_shape = context->GetInputShape(0);
    const gert::Shape *b_shape = context->GetInputShape(1);
    gert::Shape *c_shape = context->GetOutputShape(0);

    if (a_shape->GetOriginShape().GetDimNum() != 2 ||
        b_shape->GetOriginShape().GetDimNum() != 2) {
        return GRAPH_FAILED;
    }

    int64_t M = a_shape->GetOriginShape().GetDim(0);
    int64_t K_a = a_shape->GetOriginShape().GetDim(1);
    int64_t N = b_shape->GetOriginShape().GetDim(0);
    int64_t K_b = b_shape->GetOriginShape().GetDim(1);

    if (K_a != K_b) {
        return GRAPH_FAILED;
    }

    gert::Shape out;
    out.SetDimNum(2);
    out.SetDim(0, M);
    out.SetDim(1, N);
    *c_shape = out;
    return GRAPH_SUCCESS;
}

static ge::graphStatus InferDataType(gert::InferDataTypeContext *context)
{
