at::Tensor matmul_with_transposed_b_npu(const at::Tensor& A, const at::Tensor& B) {
    TORCH_CHECK(A.dim() == 2 && B.dim() == 2, "A and B must be 2D");
    TORCH_CHECK(A.size(1) == B.size(1), "K dimension mismatch: A(M,K) and B(N,K)");

    // Output shape (M, N)
    auto M = A.size(0);
    auto N = B.size(0);
    at::Tensor C = at::empty({M, N}, A.options());
    EXEC_NPU_CMD(aclnnMatmulWithTransposedBCustom, A, B, C);
    return C;
}

